px 72px rgba(0,0,0,.35);\r\n      background: #0a0f1e;\r\n    }\r\n\r\n    .hero-image { width: 100%; max-height: 700px; object-fit: cover; }\r\n\r\n    /* ── LAYOUT ── */\r\n    .layout {\r\n      margin-top: -4px;\r\n      padding: 28px 0 48px;\r\n      position: relative; z-index: 2;\r\n    }\r\n\r\n    .article-shell {\r\n      background: var(--surface);\r\n      border: 1px solid var(--line);\r\n      border-radius: 26px;\r\n      box-shadow: var(--shadow);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .article-shell::before {\r\n      content: \"\"; display: block; height: 5px;\r\n      background: linear-gradient(90deg, var(--primary-3), var(--primary), #1e3a8a);\r\n    }\r\n\r\n    .article-body { padding: 42px 40px 34px; }\r\n\r\n    .article-body p { margin: 0 0 1.2rem; font-size: 1.08rem; color: #334155; }\r\n    .article-body .lead { font-size: 1.15rem; color: #1e3052; }\r\n\r\n    .article-body h2 {\r\n      margin: 2.7rem 0 1rem;\r\n      padding-left: 14px;\r\n      border-left: 4px solid var(--primary);\r\n      font-size: clamp(1.45rem, 2vw, 2rem);\r\n      line-height: 1.28; color: var(--text-strong);\r\n      font-weight: 800; scroll-margin-top: 90px;\r\n    }\r\n\r\n    .article-body h3 {\r\n      margin: 1.8rem 0 .75rem;\r\n      font-size: 1.12rem; line-height: 1.35;\r\n      color: #172030; font-weight: 700;\r\n    }\r\n\r\n    /* ── BOXES ── */\r\n    .box {\r\n      border-radius: 18px; padding: 22px;\r\n      margin: 0 0 30px;\r\n      border: 1px solid var(--line);\r\n      background: var(--surface-soft);\r\n    }\r\n\r\n    .box strong.box-title {\r\n      display: block; margin-bottom: 10px;\r\n      font-size: 1rem; color: #1d4ed8;\r\n    }\r\n\r\n    .box-summary {\r\n      background: linear-gradient(135deg, #eff6ff, #f8faff);\r\n      border-color: #bfdbfe;\r\n      border-left: 5px solid var(--primary-3);\r\n    }\r\n\r\n    .box-toc { background: #f8fafc; border-left: 5px solid var(--primary); }\r\n    .box-toc ol { margin: 0; padding-left: 1.2rem; }\r\n    .box-toc li { margin-bottom: 8px; color: #344054; }\r\n    .box-toc a { color: var(--primary); font-weight: 600; }\r\n    .box-toc a:hover { text-decoration: underline; }\r\n\r\n    .highlight {\r\n      background: linear-gradient(135deg, #eff6ff, #fff);\r\n      border: 1px solid #bfdbfe;\r\n      border-left: 5px solid var(--primary);\r\n      border-radius: 18px; padding: 20px; margin: 26px 0;\r\n    }\r\n    .highlight strong { color: #1d4ed8; }\r\n\r\n    .highlight-warn {\r\n      background: linear-gradient(135deg, #fff7ed, #fff);\r\n      border: 1px solid #fed7aa;\r\n      border-left: 5px solid #ea580c;\r\n      border-radius: 18px; padding: 20px; margin: 26px 0;\r\n    }\r\n    .highlight-warn strong { color: #c2410c; }\r\n\r\n    .quote {\r\n      margin: 28px 0; padding: 22px;\r\n      border-radius: 18px;\r\n      background: #f8fafc;\r\n      border: 1px solid var(--line);\r\n      border-left: 4px solid var(--primary-3);\r\n      font-size: 1.05rem; color: #344054; font-weight: 500;\r\n    }\r\n\r\n    /* ── GRID / CARD ── */\r\n    .grid {\r\n      display: grid;\r\n      grid-template-columns: repeat(2, minmax(0,1fr));\r\n      gap: 16px; margin: 28px 0;\r\n    }\r\n\r\n    .card {\r\n      background: #f8fafc;\r\n      border: 1px solid var(--line);\r\n      border-radius: 18px; padding: 18px;\r\n    }\r\n\r\n    .card h4 { margin: 0 0 8px; color: #111827; font-size: 1rem; font-weight: 800; }\r\n    .card p  { margin: 0; font-size: .98rem; color: #475467; }\r\n\r\n    /* ── FACTS ── */\r\n    .facts {\r\n      background: linear-gradient(135deg, #060d1f, #0f1f45);\r\n      color: #fff; border-radius: 22px;\r\n      padding: 28px; margin: 30px 0;\r\n      box-shadow: 0 18px 40px rgba(15,23,42,.18);\r\n    }\r\n\r\n    .facts h3 { margin: 0 0 16px; color: #bfdbfe; font-size: 1.16rem; }\r\n    .facts ul { margin: 0; padding-left: 1.2rem; }\r\n    .facts li { margin-bottom: 10px; color: rgba(255,255,255,.92); }\r\n\r\n    /* ── FIGURE ── */\r\n    figure.media {\r\n      margin: 34px 0; overflow: hidden;\r\n      border-radius: 22px; background: #fff;\r\n      border: 1px solid var(--line);\r\n      box-shadow: 0 14px 30px rgba(0,0,0,.06);\r\n    }\r\n\r\n    figure.media img { width: 100%; }\r\n\r\n    figure.media figcaption {\r\n      padding: 14px 16px;\r\n      border-top: 1px solid var(--line);\r\n      background: #fff; color: var(--muted);\r\n      font-size: .93rem;\r\n    }\r\n\r\n    /* ── FRAKSIYONLAR ── */\r\n    .fraction-list {\r\n      margin: 24px 0;\r\n      display: flex; flex-direction: column; gap: 12px;\r\n    }\r\n\r\n    .fraction-item {\r\n      display: flex; gap: 14px; align-items: flex-start;\r\n      padding: 16px; border-radius: 14px;\r\n      border: 1px solid var(--line);\r\n      background: #f8fafc;\r\n    }\r\n\r\n    .fraction-badge {\r\n      flex-shrink: 0;\r\n      width: 42px; height: 42px; border-radius: 50%;\r\n      display: flex; align-items: center; justify-content: center;\r\n      font-size: .78rem; font-weight: 800; color: #fff; text-align: center; line-height: 1.1;\r\n      background: linear-gradient(135deg, var(--primary-3), var(--primary));\r\n    }\r\n\r\n    .fraction-item h4 { margin: 0 0 4px; font-size: 1rem; color: #1d4ed8; font-weight: 800; }\r\n    .fraction-item p  { margin: 0; font-size: .97rem; color: #334155; }\r\n\r\n    /* ── FINAL NOTE ── */\r\n    .final-note {\r\n      margin-top: 34px;\r\n      background: linear-gradient(135deg, #eff6ff, #fff);\r\n      border: 1px solid #bfdbfe;\r\n      border-radius: 18px; padding: 22px;\r\n    }\r\n    .final-note h3 { margin-top: 0; color: #1d4ed8; }\r\n\r\n    /* ── SOURCES ── */\r\n    .sources {\r\n      margin-top: 36px;\r\n      padding: 28px 24px;\r\n      border-radius: 20px;\r\n      background: linear-gradient(180deg, #ffffff 0%, #f8fafc 100%);\r\n      border: 1px solid var(--line);\r\n      box-shadow: 0 14px 34px rgba(15,23,42,.06);\r\n    }\r\n\r\n    .sources h3 {\r\n      margin: 0 0 18px;\r\n      font-size: 1.22rem; font-weight: 800;\r\n      color: var(--text-strong); letter-spacing: -.02em;\r\n    }\r\n\r\n    .source-list { margin: 0; padding-left: 1.2rem; }\r\n\r\n    .source-item {\r\n      margin-bottom: 16px;\r\n      padding: 14px 16px;\r\n      border: 1px solid var(--line);\r\n      border-radius: 14px;\r\n      background: #fff;\r\n      transition: transform .2s ease, box-shadow .2s ease, border-color .2s ease;\r\n    }\r\n\r\n    .source-item:hover {\r\n      transform: translateY(-2px);\r\n      border-color: #bfdbfe;\r\n      box-shadow: 0 10px 24px rgba(37,99,235,.08);\r\n    }\r\n\r\n    .source-link {\r\n      display: inline-block;\r\n      font-weight: 700; font-size: 1rem;\r\n      color: #1d4ed8; text-decoration: none;\r\n      margin-bottom: 6px;\r\n    }\r\n\r\n    .source-link:hover { color: #1e40af; text-decoration: underline; }\r\n\r\n    .source-original {\r\n      display: block; margin-bottom: 6px;\r\n      font-size: .92rem; color: #64748b;\r\n    }\r\n\r\n    .source-meta {\r\n      display: block; font-size: .95rem;\r\n      line-height: 1.7; color: #334155;\r\n    }\r\n\r\n    .source-meta em { font-style: italic; color: #0f172a; }\r\n\r\n    .source-note {\r\n      display: inline-block; margin-top: 6px;\r\n      font-size: .88rem; color: #475569;\r\n      background: #eff6ff;\r\n      border: 1px solid #bfdbfe;\r\n      padding: 4px 8px; border-radius: 999px;\r\n    }\r\n\r\n    /* ── BAŞA DÖN ── */\r\n    .back-top {\r\n      position: fixed;\r\n      right: 20px; bottom: 20px;\r\n      left: auto; top: auto;\r\n      display: block !important;\r\n      width: 44px !important; height: 44px !important;\r\n      border: none; border-radius: 50%;\r\n      background: #060d1f; color: #fff;\r\n      font-size: 20px; line-height: 44px;\r\n      text-align: center;\r\n      box-shadow: 0 4px 14px rgba(15,23,42,.32);\r\n      cursor: pointer; z-index: 9998;\r\n      opacity: 0; visibility: hidden; pointer-events: none;\r\n      transition: opacity .25s, visibility .25s, background .2s;\r\n      padding: 0; margin: 0;\r\n      -webkit-appearance: none; appearance: none;\r\n    }\r\n\r\n    .back-top.show { opacity: 1; visibility: visible; pointer-events: auto; }\r\n    .back-top:hover { background: var(--primary); }\r\n\r\n    .footer-space { height: 34px; }\r\n\r\n    /* ════ RESPONSIVE ════ */\r\n    @media (max-width: 900px) {\r\n      .article-body { padding: 28px 22px 24px; }\r\n      .grid { grid-template-columns: 1fr; }\r\n    }\r\n\r\n    @media (max-width: 640px) {\r\n      .container { width: 100%; padding-inline: 0; }\r\n\r\n      .badge {\r\n        display: inline-block;\r\n        border-radius: 12px;\r\n        font-size: .78rem;\r\n        padding: 7px 12px;\r\n        white-space: normal;\r\n      }\r\n\r\n      .hero { padding: 42px 12px 18px; }\r\n      .hero h1 { font-size: 1.9rem; }\r\n      .hero-sub { font-size: .98rem; }\r\n      .hero-meta span { font-size: .8rem; padding: 8px 10px; }\r\n      .hero-image-wrap { border-radius: 16px; margin-top: 20px; }\r\n\r\n      .layout { padding: 0 0 30px; }\r\n\r\n      .article-shell {\r\n        width: 100vw;\r\n        position: relative;\r\n        left: 50%;\r\n        margin-left: -50vw;\r\n        border-radius: 0;\r\n        border-left: none;\r\n        border-right: none;\r\n        box-shadow: none;\r\n      }\r\n\r\n      .article-shell::before { display: none; }\r\n\r\n      .article-body { padding: 18px 14px 24px; }\r\n      .article-body p { font-size: 1rem; }\r\n      .article-body .lead { font-size: 1.03rem; }\r\n\r\n      .box, .highlight, .highlight-warn, .quote, .final-note, .sources { border-radius: 12px; }\r\n      .card { border-radius: 12px; }\r\n      .fraction-item { border-radius: 10px; padding: 13px; }\r\n      .facts { border-radius: 14px; padding: 18px 14px; }\r\n      figure.media { border-radius: 14px; margin: 22px 0; }\r\n\r\n      .back-top { right: 14px; bottom: 14px; }\r\n    }\r\n\r\n    @media (max-width: 380px) {\r\n      .article-body { padding: 14px 10px 20px; }\r\n    }\r\n  </style>\r\n</head>\r\n<body id=\"top\">\r\n  <a href=\"#main-content\" class=\"skip-link\">İçeriğe geç</a>\r\n  <div class=\"reading-progress\" id=\"readingProgress\"></div>\r\n\r\n  <header class=\"hero\">\r\n    <div class=\"container hero-inner\">\r\n      <span class=\"badge\">Spor Beslenmesi • Klinik Derleme • Bilimsel Rehber</span>\r\n\r\n      <h1>Whey Protein: Faydaları, Etkileri ve Olası Riskleri</h1>\r\n\r\n      <p class=\"hero-sub\">\r\n        Whey protein, sporcu beslenmesinde en sık tercih edilen takviyelerden biridir.\r\n        Bu derleme; kas gelişimi, iştah kontrolü, metabolik etkiler, bağırsak sağlığı\r\n        ve olası riskleri bilimsel veriler eşliğinde değerlendirmektedir.\r\n      </p>\r\n\r\n      <div class=\"hero-meta\" aria-label=\"Makale bilgileri\">\r\n        <span>Okuma Süresi: 12–15 Dakika</span>\r\n        <span>Odak: Fizyoloji, Metabolizma, Riskler</span>\r\n        <span>İçerik: Klinik Literatür Bazlı</span>\r\n        <span>✍️ FitRehber</span>\r\n      </div>\r\n\r\n      <div class=\"hero-image-wrap\">\r\n        <img\r\n          class=\"hero-image\"\r\n          src=\"/media/ckeditor_resimleri/1000103992-3ed4b680f34a.jpg\"\r\n          alt=\"Whey protein takviyesi ve sporcu beslenmesi görseli\"\r\n          width=\"1200\" height=\"680\"\r\n          fetchpriority=\"high\">\r\n      </div>\r\n    </div>\r\n  </header>\r\n\r\n  <main id=\"main-content\" class=\"layout\">\r\n    <div class=\"container\">\r\n      <article class=\"article-shell\">\r\n        <div class=\"article-body\" id=\"articleContent\">\r\n\r\n          <!-- İÇİNDEKİLER -->\r\n          <nav class=\"box box-toc\" aria-label=\"İçindekiler\">\r\n            <strong class=\"box-title\">📋 İçindekiler</strong>\r\n            <ol>\r\n              <li><a href=\"#ozet\">Özet</a></li>\r\n              <li><a href=\"#giris\">Giriş ve Biyokimyasal Yapı</a></li>\r\n              <li><a href=\"#kas\">Kas Gelişimi ve Optimal Dozaj</a></li>\r\n              <li><a href=\"#kilo\">Tokluk ve Metabolik Etkiler</a></li>\r\n              <li><a href=\"#immun\">Bağışıklık ve Bağırsak Mikrobiyomu</a></li>\r\n              <li><a href=\"#risk\">Olası Riskler ve Dikkat Edilmesi Gerekenler</a></li>\r\n              <li><a href=\"#sonuc\">Sonuç</a></li>\r\n            </ol>\r\n          </nav>\r\n\r\n          <!-- ÖZET -->\r\n          <h2 id=\"ozet\">Özet</h2>\r\n\r\n          <section class=\"box box-summary\">\r\n            <strong class=\"box-title\">Bu makale ne anlatıyor?</strong>\r\n            <p>\r\n              Peynir altı suyu proteini, yüksek biyolojik değeri ve hızlı emilim kapasitesi sayesinde\r\n              hem spor beslenmesinde hem de klinik destek programlarında yaygın olarak kullanılmaktadır.\r\n            </p>\r\n            <p>\r\n              Bu makale, whey proteinin kas gelişimi, tokluk hissi, kardiyometabolik göstergeler ve\r\n              bağışıklık sistemi üzerindeki etkilerini değerlendirirken; akne oluşumu ve ağır metal\r\n              maruziyeti gibi potansiyel riskleri de ele almaktadır.\r\n            </p>\r\n          </section>\r\n\r\n          <!-- BÖLÜM 1 -->\r\n          <h2 id=\"giris\">1. Giriş ve Biyokimyasal Yapı</h2>\r\n\r\n          <p class=\"lead\">\r\n            Peynir altı suyu, peynir üretimi sırasında ortaya çıkan ve biyolojik açıdan değerli\r\n            protein fraksiyonları içeren bir süt yan ürünüdür. Başta beta-laktoglobulin,\r\n            alfa-laktalbumin ve serum albümini olmak üzere çeşitli biyoaktif bileşenler içermesi,\r\n            whey proteinini fonksiyonel beslenme açısından öne çıkarmaktadır.\r\n          </p>\r\n\r\n          <p>\r\n            Günümüzde whey protein; konsantre (WPC), izolat (WPI) ve hidrolize (WPH) form olarak\r\n            üretilmektedir. Her formun protein saflığı, sindirim hızı ve hedef kullanıcı profili\r\n            birbirinden farklıdır.\r\n          </p>\r\n\r\n          <div class=\"fraction-list\">\r\n            <div class=\"fraction-item\">\r\n              <div class=\"fraction-badge\">WPC</div>\r\n              <div>\r\n                <h4>Konsantre (WPC)</h4>\r\n                <p>En yaygın kullanılan formdur. Protein oranı değişkendir ve belirli miktarda laktoz\r\n                ile yağ içerebilir. Maliyet-verim dengesi açısından öne çıkar.</p>\r\n              </div>\r\n            </div>\r\n            <div class=\"fraction-item\">\r\n              <div class=\"fraction-badge\">WPI</div>\r\n              <div>\r\n                <h4>İzolat (WPI)</h4>\r\n                <p>Daha yüksek protein saflığına sahiptir. Laktoz oranı düşüktür; bu nedenle\r\n                sindirim hassasiyeti olan bireylerde daha sık tercih edilir.</p>\r\n              </div>\r\n            </div>\r\n            <div class=\"fraction-item\">\r\n              <div class=\"fraction-badge\">WPH</div>\r\n              <div>\r\n                <h4>Hidrolizat (WPH)</h4>\r\n                <p>Kısmen parçalanmış yapısı sayesinde daha hızlı emilir. Allerjen potansiyeli\r\n                azaltılmış olmakla birlikte maliyeti diğer formlara kıyasla daha yüksektir.</p>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"grid\">\r\n            <div class=\"card\">\r\n              <h4>Beta-Laktoglobulin</h4>\r\n              <p>İnek sütünde en bol bulunan whey fraksiyonu. Yüksek lösin içeriğiyle kas protein\r\n              sentezini tetikleme kapasitesi yüksektir.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Alfa-Laktalbumin</h4>\r\n              <p>Anne sütüne en çok benzeyen fraksiyon. Triptofan bakımından zengindir; serotonin\r\n              öncülü olarak ruh hali ve uyku kalitesini dolaylı biçimde etkileyebilir.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Serum Albümini</h4>\r\n              <p>Antioksidan savunmada kritik rol oynayan sistein ve sistin kaynağıdır. Glutatyon\r\n              sentezinin temel öncülü olarak hücre içi koruyucu mekanizmaları destekler.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Glikomakropeptid (GMP)</h4>\r\n              <p>Prebiyotik etkileri bilimsel çalışmalarla desteklenen biyoaktif bir peptittir.\r\n              Bağırsak sağlığı ve mikrobiyom dengesi üzerinde olumlu etkiler gösterebilir.</p>\r\n            </div>\r\n          </div>\r\n\r\n          <!-- BÖLÜM 2 -->\r\n          <h2 id=\"kas\">2. Kas Gelişimi ve Optimal Dozaj</h2>\r\n\r\n          <p class=\"lead\">\r\n            Whey proteinin en çok araştırılan etkilerinden biri kas protein sentezini desteklemesidir.\r\n            Özellikle direnç antrenmanıyla birlikte kullanıldığında, yeterli günlük protein alımı ve\r\n            uygun lösin miktarıyla kas kütlesi ve kuvvet gelişimine anlamlı katkı sağlayabilmektedir.\r\n          </p>\r\n\r\n          <p>\r\n            Uluslararası Spor Beslenmesi Derneği (ISSN) kılavuzlarına göre yağsız kas kütlesini artırmak\r\n            ya da korumak için günlük protein alımının vücut ağırlığı başına 1.4–2.0 g/kg düzeyinde\r\n            olması önerilmektedir. Tek porsiyonda ise 20–40 gram protein ve 700–3000 mg lösin, kas\r\n            protein sentezini etkili biçimde uyarmak için gerekli eşik değerler olarak öne çıkmaktadır.\r\n          </p>\r\n\r\n          <div class=\"highlight\">\r\n            <strong>Temel nokta:</strong> Tek porsiyonda alınan protein miktarı ve lösin içeriği,\r\n            kas protein sentezinin uyarılmasında belirleyici rol oynar. Bu eşiklerin altında kalan\r\n            alımlar, antrenman sonrası kas onarımı için yeterli sinyal oluşturamayabilir.\r\n          </div>\r\n\r\n          <section class=\"facts\" aria-label=\"Kas gelişimi için temel parametreler\">\r\n            <h3>💪 Kas Gelişimi için Temel Parametreler</h3>\r\n            <ul>\r\n              <li>Günlük optimal protein alımı: vücut ağırlığı başına <strong>1.4–2.0 g/kg</strong></li>\r\n              <li>Tek porsiyon için önerilen miktar: <strong>20–40 g protein</strong></li>\r\n              <li>Kas protein sentezi için minimum lösin: <strong>700–3000 mg/porsiyon</strong></li>\r\n              <li>78 çalışma ve 4755 katılımcıyı kapsayan 2026 meta-analizi: direnç antrenmanıyla\r\n              birlikte kullanıldığında kas kütlesi ve kuvvet kazanımında güçlü ve tutarlı etki</li>\r\n              <li>\"Native Whey\" formu standart konsantreye kıyasla ek klinik üstünlük sunmuyor</li>\r\n            </ul>\r\n          </section>\r\n\r\n          <!-- Resim 2 -->\r\n          <figure class=\"media\">\r\n            <img\r\n              src=\"/media/ckeditor_resimleri/1000103993-f53c032c0a09.jpg\"\r\n              alt=\"Whey protein kas gelişimini destekleyen sporcu beslenmesi görseli\"\r\n              loading=\"lazy\" width=\"1200\" height=\"700\">\r\n            <figcaption>\r\n              Direnç antrenmanıyla birleştirilen whey protein takviyesi, kas kütlesi ve kuvvet\r\n              kazanımında plaseboya kıyasla bilimsel olarak güçlü sonuçlar ortaya koymaktadır.\r\n            </figcaption>\r\n          </figure>\r\n\r\n          <!-- BÖLÜM 3 -->\r\n          <h2 id=\"kilo\">3. Tokluk ve Metabolik Etkiler</h2>\r\n\r\n          <p class=\"lead\">\r\n            Whey protein yalnızca kas gelişimiyle sınırlı değildir. Tokluk hissini artırması,\r\n            enerji alımını azaltma potansiyeli ve besinlerin termojenik etkisine katkısı nedeniyle\r\n            kilo yönetimi açısından da dikkat çekmektedir.\r\n          </p>\r\n\r\n          <p>\r\n            Whey protein, soya proteinine kıyasla besinlerin termojenik etkisini (TEF) yaklaşık\r\n            %14.5 oranında daha fazla artırarak metabolik enerji harcamasını yükseltiyor. Bunun\r\n            yanında iştah düzenlenmesini inceleyen meta-analizler, whey proteininin tokluk hissini\r\n            güçlendirdiğini ve bireylerin sonraki öğünlerde daha az yemek yeme eğilimine girdiğini\r\n            tutarlı biçimde göstermektedir.\r\n          </p>\r\n\r\n          <div class=\"grid\">\r\n            <div class=\"card\">\r\n              <h4>Tokluk</h4>\r\n              <p>İştah kontrolünü destekleyebilir ve enerji alımını azaltmaya yardımcı olabilir.\r\n              GLP-1 ve PYY gibi tokluk hormonları üzerinde olumlu etkisi belgelenmiştir.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Termojenik Etki</h4>\r\n              <p>Sindirim sürecinde enerji harcamasını artırabilir. Soya proteinine kıyasla yaklaşık\r\n              %14.5 daha yüksek termojenik etki saptanmıştır.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Lipid Profili</h4>\r\n              <p>Bazı çalışmalarda LDL ve total kolesterol üzerinde olumlu etkiler bildirilmiştir;\r\n              özellikle 50 yaş altında ve egzersizle birleştirildiğinde bu etki daha belirgindir.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Kardiyovasküler Destek</h4>\r\n              <p>Sistolik kan basıncı üzerinde hafif olumlu etki raporlanmıştır. Kesin mekanizma\r\n              henüz tam aydınlatılamamış olsa da biyoaktif peptitlerin rolü olduğu düşünülmektedir.</p>\r\n            </div>\r\n          </div>\r\n\r\n          <div class=\"quote\">\r\n            Whey protein, hem termojenik etkisiyle kalori dengesi üzerinde hem de tokluk hormonları\r\n            üzerinden iştah kontrolünde çift yönlü bir metabolik avantaj sunmaktadır.\r\n          </div>\r\n\r\n          <!-- BÖLÜM 4 -->\r\n          <h2 id=\"immun\">4. Bağışıklık ve Bağırsak Mikrobiyomu</h2>\r\n\r\n          <p class=\"lead\">\r\n            Whey proteinin bazı fraksiyonları, glutatyon sentezine katkı sağlayarak antioksidan\r\n            savunmayı destekleyebilir. Ayrıca glikomakropeptid gibi bileşenler, bağırsak\r\n            mikrobiyotası üzerinde olumlu etkiler oluşturabilecek prebiyotik özellikler gösterebilir.\r\n          </p>\r\n\r\n          <p>\r\n            Hücrenin temel antioksidan savunma molekülü olan glutatyonun (GSH) sentezi, büyük\r\n            ölçüde sistein arzına bağlıdır. Whey protein izolatları, yüksek sistein ve sistin\r\n            içerikleri sayesinde hücre içi GSH düzeylerini artırarak hem immün sistemi hem de\r\n            nörolojik koruma mekanizmalarını dolaylı biçimde destekleyebilmektedir.\r\n          </p>\r\n\r\n          <div class=\"highlight\">\r\n            <strong>Prebiyotik etkisi:</strong> Whey proteinde bulunan glikomakropeptid (GMP),\r\n            bağırsakta başta <em>Bifidobacterium</em> olmak üzere yararlı bakteri topluluklarının\r\n            büyümesini destekler. Bu etki, bağırsak bütünlüğü ve bağışıklık dengesi için\r\n            önemli bir dolaylı katkı sağlayabilmektedir.\r\n          </div>\r\n\r\n          <section class=\"facts\" aria-label=\"Bağışıklık ve mikrobiyom etkileri\">\r\n            <h3>🛡️ Bağışıklık ve Mikrobiyom Etkileri</h3>\r\n            <ul>\r\n              <li>Sistein + sistin → hücre içi glutatyon (GSH) sentezi artışı → oksidatif strese karşı direnç</li>\r\n              <li>GSH desteği, nöroprotektif etki ve bağışıklık homeostaziyle ilişkilendirilmektedir</li>\r\n              <li>GMP fraksiyonu → <em>Bifidobacterium</em> büyümesini destekler → bağırsak mikrobiyom dengesi</li>\r\n              <li>Laktoferrin fraksiyonu → antimikrobiyal ve anti-inflamatuvar aktivite</li>\r\n              <li>İmmünglobulin fraksiyonları → mukozal bağışıklık savunmasına katkı</li>\r\n            </ul>\r\n          </section>\r\n\r\n          <!-- Resim 3 -->\r\n          <figure class=\"media\">\r\n            <img\r\n              src=\"/media/ckeditor_resimleri/1000103994-47502b76f79b.jpg\"\r\n              alt=\"Whey proteinin bağışıklık ve bağırsak sağlığı üzerindeki etkileri\"\r\n              loading=\"lazy\" width=\"1200\" height=\"700\">\r\n            <figcaption>\r\n              Whey proteinin metabolik ve fizyolojik etkilerine genel bakış: bağırsak mikrobiyomunu\r\n              ve antioksidan savunmayı aynı anda destekleyen çok yönlü bir profil.\r\n            </figcaption>\r\n          </figure>\r\n\r\n          <!-- BÖLÜM 5 -->\r\n          <h2 id=\"risk\">5. Olası Riskler ve Dikkat Edilmesi Gerekenler</h2>\r\n\r\n          <p class=\"lead\">\r\n            Whey protein birçok birey için yararlı bir takviye olsa da, yüksek miktarda ve uzun\r\n            süreli kullanım bazı istenmeyen etkilerle ilişkilendirilebilir. Özellikle akne eğilimi\r\n            olan bireylerde hormonal yanıtlar dikkatle değerlendirilmelidir. Bunun yanında ürün\r\n            kalitesi ve içerik güvenliği de göz önünde bulundurulmalıdır.\r\n          </p>\r\n\r\n          <p>\r\n            Whey proteinin insülin ve IGF-1 düzeylerini yükselten hormonal etkisi, bazı bireylerde\r\n            cilt sorunlarına yol açabilecek bir dizi biyolojik mekanizmayı tetikleyebilmektedir.\r\n            Bu süreç; sebum üretiminin artması ve gözeneklerin tıkanması yoluyla özellikle gövde\r\n            bölgesinde akne lezyonlarının gelişmesini kolaylaştırabilir.\r\n          </p>\r\n\r\n          <div class=\"highlight-warn\">\r\n            <strong>Akne riski:</strong> Akne eğilimi bulunan bireylerde whey proteinin, hormonal\r\n            mekanizmalar (IGF-1 artışı → mTORC1 aktivasyonu → aşırı sebum üretimi) üzerinden\r\n            cilt üzerinde olumsuz etkiler oluşturabileceği klinik vakalarla desteklenmektedir.\r\n            Akne sorunu yaşayan bireylerin bir dermatoloğa danışması önerilir.\r\n          </div>\r\n\r\n          <div class=\"highlight-warn\">\r\n            <strong>Ağır metal riski:</strong> 2025 yılına ait laboratuvar analizleri, özellikle\r\n            \"organik\" ibaresi taşıyan protein tozlarının konvansiyonel ürünlere kıyasla ortalama\r\n            <strong>3 kat daha fazla kurşun</strong> ve <strong>2 kat daha fazla kadmiyum</strong>\r\n            içerebildiğini ortaya koymuştur. Kronik maruziyet sınırları konusunda tüketicilerin\r\n            bilinçli olması büyük önem taşımaktadır.\r\n          </div>\r\n\r\n          <div class=\"grid\">\r\n            <div class=\"card\">\r\n              <h4>Akne ve Cilt</h4>\r\n              <p>Hormonal mekanizmalar üzerinden sebum üretimini artırabilir. Akne eğilimi olan\r\n              bireyler whey kullanımını bir dermatoloğa danışarak değerlendirmelidir.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Kurşun Maruziyeti</h4>\r\n              <p>\"Organik\" etiketli ürünlerde konvansiyonel ürünlere kıyasla ortalama 3 kat daha\r\n              yüksek kurşun saptanmıştır. Topraktan hammaddeye geçiş bu farkı açıklıyor olabilir.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Kadmiyum Birikimi</h4>\r\n              <p>Organik kaynaklı ürünlerde 2 kat daha fazla kadmiyum tespit edilmiştir. Uzun\r\n              vadeli maruziyet böbrek sağlığı açısından izlenmesi gereken bir risk faktörüdür.</p>\r\n            </div>\r\n            <div class=\"card\">\r\n              <h4>Kalite Kontrol</h4>\r\n              <p>Bağımsız testlerden geçmiş ve içerik şeffaflığı sağlayan ürünlerin tercih edilmesi\r\n              daha güvenli bir yaklaşım sunar. NSF, Informed Sport gibi sertifikalar rehber olabilir.</p>\r\n            </div>\r\n          </div>\r\n\r\n          <!-- SONUÇ -->\r\n          <h2 id=\"sonuc\">Sonuç</h2>\r\n\r\n          <section class=\"final-note\">\r\n            <h3>Genel Değerlendirme</h3>\r\n            <p>\r\n              Sonuç olarak whey protein, kas gelişimi, tokluk kontrolü ve bazı metabolik göstergeler\r\n              üzerinde olumlu etkiler sunabilen güçlü bir takviyedir. Direnç antrenmanıyla\r\n              birleştirildiğinde kas kütlesi ve kuvvet kazanımına sağladığı katkı, geniş çaplı\r\n              meta-analizlerle tutarlı biçimde desteklenmektedir.\r\n            </p>\r\n            <p style=\"margin-bottom:0\">\r\n              Ancak olası dermatolojik etkiler ve ürün kalitesiyle ilgili riskler göz önünde\r\n              bulundurulmalı; kullanım dozu bireysel ihtiyaçlara, toleransa ve sağlık durumuna\r\n              göre planlanmalıdır. Whey protein etkili bir beslenme desteği olabilir —\r\n              dozaj, bireysel tolerans ve ürün kalitesi birlikte değerlendirildiğinde.\r\n            </p>\r\n          </section>\r\n\r\n          <!-- KAYNAKÇA -->\r\n          <section class=\"sources\" aria-label=\"Bilimsel kaynaklar\">\r\n            <h3>Bilimsel Kaynaklar</h3>\r\n\r\n            <ol class=\"source-list\">\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://doi.org/10.1186/1476-511X-6-25\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  İnsan Beslenmesinde İnek Sütü: Bir Derleme\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: Bovine milk in human nutrition — a review</span>\r\n                <span class=\"source-meta\">\r\n                  Haug A, Høstmark AT, Harstad OM. (2007).\r\n                  <em>Lipids in Health and Disease</em>, 6, 25.\r\n                </span>\r\n              </li>\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://doi.org/10.3390/nu10020180\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  Direnç Antrenmanıyla Kas Hipertrofisini Desteklemede Diyet Proteininin Rolüne Güncel Bir Bakış\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: Recent Perspectives Regarding the Role of Dietary Protein for the Promotion of Muscle Hypertrophy with Resistance Exercise Training</span>\r\n                <span class=\"source-meta\">\r\n                  Stokes T, Hector AJ, Morton RW et al. (2018).\r\n                  <em>Nutrients</em>, 10(2), 180.\r\n                </span>\r\n              </li>\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://doi.org/10.1186/s12970-017-0177-8\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  Uluslararası Spor Beslenmesi Derneği Görüş Metni: Protein ve Egzersiz\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: International Society of Sports Nutrition Position Stand: Protein and Exercise</span>\r\n                <span class=\"source-meta\">\r\n                  Jäger R, Kerksick CM, Campbell BI et al. (2017).\r\n                  <em>Journal of the International Society of Sports Nutrition</em>, 14, 20.\r\n                </span>\r\n                <span class=\"source-note\">ISSN rehber kaynağı</span>\r\n              </li>\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://doi.org/10.1093/jn/136.2.533S\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  Lösin, Egzersiz Sonrası İskelet Kasında Protein Sentezinin Başlatılmasını Düzenler\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: Leucine regulates translation initiation of protein synthesis in skeletal muscle after exercise</span>\r\n                <span class=\"source-meta\">\r\n                  Norton LE, Layman DK. (2006).\r\n                  <em>Journal of Nutrition</em>, 136(2), 533S–537S.\r\n                </span>\r\n              </li>\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://doi.org/10.3945/ajcn.110.005850\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  Termogenez ve Metabolizmayı Hedefleyen Protein Tercihleri\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: Protein choices targeting thermogenesis and metabolism</span>\r\n                <span class=\"source-meta\">\r\n                  Acheson KJ, Blondel-Lubrano A, Oguike S et al. (2011).\r\n                  <em>American Journal of Clinical Nutrition</em>, 93(3), 525–534.\r\n                </span>\r\n              </li>\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://doi.org/10.1016/j.clnesp.2017.04.002\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  Whey Protein Takviyesinin Kısa ve Uzun Dönem İştah Üzerindeki Etkisi: Meta-Analiz\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: Effect of whey protein supplementation on long and short term appetite: A meta-analysis of randomized controlled trials</span>\r\n                <span class=\"source-meta\">\r\n                  Mollahosseini M, Shab-Bidar S, Rahimi MH, Djafarian K. (2017).\r\n                  <em>Clinical Nutrition ESPEN</em>, 20, 34–40.\r\n                </span>\r\n              </li>\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://pubmed.ncbi.nlm.nih.gov/11205219/\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  Whey Protein Konsantresi (WPC) ve Kanser Tedavisinde Glutatyon Düzenlenmesi\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: Whey protein concentrate (WPC) and glutathione modulation in cancer treatment</span>\r\n                <span class=\"source-meta\">\r\n                  Bounous G. (2000).\r\n                  <em>Anticancer Research</em>, 20(6C), 4785–4792.\r\n                </span>\r\n                <span class=\"source-note\">PubMed bağlantısı</span>\r\n              </li>\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://doi.org/10.1111/j.1600-0625.2009.00924.x\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  Akne Vulgarisin Patogenezinde İnsülin, IGF-1, Yüksek Glisemik Beslenme ve Süt Tüketiminin Rolü\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: Role of insulin, insulin-like growth factor-1, hyperglycaemic food and milk consumption in the pathogenesis of acne vulgaris</span>\r\n                <span class=\"source-meta\">\r\n                  Melnik BC, Schmitz G. (2009).\r\n                  <em>Experimental Dermatology</em>, 18(10), 833–841.\r\n                </span>\r\n              </li>\r\n\r\n              <li class=\"source-item\">\r\n                <a class=\"source-link\" href=\"https://doi.org/10.2340/00015555-1358\" target=\"_blank\" rel=\"noopener noreferrer\">\r\n                  Aknede Beslenme: Besin Sinyallemesinin Rolüne Dair Ek Kanıtlar\r\n                </a>\r\n                <span class=\"source-original\">Orijinal başlık: Diet in acne: further evidence for the role of nutrient signalling in acne pathogenesis</span>\r\n                <span class=\"source-meta\">\r\n                  Melnik BC. (2012).\r\n                  <em>Acta Dermato-Venereologica</em>, 92(3), 228–231.\r\n                </span>\r\n              </li>\r\n\r\n            </ol>\r\n          </section>\r\n\r\n        </div>\r\n      </article>\r\n    </div>\r\n  </main>\r\n\r\n  <button id=\"backToTopBtn\" class=\"back-top\" aria-label=\"Sayfanın başına dön\">↑</button>\r\n  <div class=\"footer-space\"></div>\r\n\r\n  <script>\r\n    const readingProgress = document.getElementById(\'readingProgress\');\r\n    const articleContent  = document.getElementById(\'articleContent\');\r\n    const backToTopBtn    = document.getElementById(\'backToTopBtn\');\r\n    let ticking = false;\r\n\r\n    function updateOnScroll() {\r\n      const contentTop    = articleContent.offsetTop;\r\n      const contentHeight = articleContent.offsetHeight;\r\n      const scrollY       = window.scrollY + 100;\r\n      let progress = scrollY > contentTop\r\n        ? ((scrollY - contentTop) / contentHeight) * 100 : 0;\r\n      readingProgress.style.width = Math.max(0, Math.min(progress, 100)) + \'%\';\r\n      backToTopBtn.classList.toggle(\'show\', window.scrollY > 500);\r\n      ticking = false;\r\n    }\r\n\r\n    window.addEventListener(\'scroll\', () => {\r\n      if (!ticking) { window.requestAnimationFrame(updateOnScroll); ticking = true; }\r\n    });\r\n\r\n    window.addEventListener(\'load\', updateOnScroll);\r\n\r\n    backToTopBtn.addEventListener(\'click\', () => {\r\n      window.scrollTo({ top: 0, behavior: \'smooth\' });\r\n    });\r\n  </script>\r\n</body>\r\n</html>','','haber','2026-03-15 11:23:38.516385',3,3),(466,'Kalori açığında akşam açlığını nasıl yönetiyorsunuz?','Yaklaşık üç haftadır kalori açığındayım. Gündüz iyi gidiyor ama akşam 22.00 civarı ciddi açlık geliyor. Proteinimi ve suyu artırdım ama yine de zorlanıyorum. Siz bunu öğün dağılımıyla mı, düşük kalorili atıştırmalıklarla mı çözüyorsunuz?','','soru','2026-05-22 03:50:38.862307',478,1),(467,'Yeni başlayan biri için full body mi PPL mi daha mantıklı?','Spor salonuna düzenli olarak yeni başladım. Haftada 3 gün kesin gidebiliyorum, bazen 4 oluyor. Sosyal medyada herkes PPL öneriyor ama full body daha mantıklı gibi geliyor. Sizce başlangıç için hangisi daha sürdürülebilir?','','soru','2026-05-20 03:50:38.862307',465,2),(468,'Kreatini ne zaman almak daha iyi, antrenman öncesi mi sonrası mı?','Kreatine başlayacağım ama zamanlama konusunda çok farklı şeyler okudum. Birileri antrenman öncesi performans için diyor, bazıları sonrası daha iyi diyor. Gerçekten zamanlama fark ediyor mu?','','soru','2026-05-18 03:50:38.862307',472,3),(469,'Whey protein şart mı yoksa besinden tamamlamak yeterli mi?','Günlük protein hedefim 120 gram civarı. Tavuk, yumurta, yoğurt ile çoğu gün tamamlıyorum ama bazen zor oluyor. Whey almak şart mı, yoksa sadece pratiklik mi?','','soru','2026-05-16 03:50:38.862307',483,3),(470,'Squat sırasında dizlerin öne gitmesi gerçekten problem mi?','Squat yaparken dizlerim parmak ucunu biraz geçiyor. Salonda biri bunun kesin yanlış olduğunu söyledi ama farklı kaynaklarda normal olduğu yazıyor. Ağrım yok, formu nasıl değerlendirmek lazım?','','soru','2026-05-14 03:50:38.862307',474,2),(471,'Kardiyo kas gelişimini engeller mi?','Haftada 4 gün ağırlık çalışıyorum. Yağ oranımı düşürmek için 2-3 gün kardiyo eklemek istiyorum ama kas kazanımını engeller mi diye kararsız kaldım.','','soru','2026-05-12 03:50:38.862307',471,2),(472,'Magnezyum ve uyku kalitesi hakkında deneyiminiz var mı?','Son dönemde uykuya dalmakta zorlanıyorum. Magnezyum glisinat önerenler var ama supplemente hemen atlamak istemiyorum. Deneyimi olan var mı?','','soru','2026-05-10 03:50:38.862307',475,3),(473,'Protein hedefini tuttururken yağ oranı yükseliyor, neyi yanlış yapıyorum?','Protein artırınca genelde peynir, kuruyemiş ve et miktarı da artıyor; bu sefer yağ kalori çok yükseliyor. Daha dengeli protein kaynakları önerir misiniz?','','soru','2026-05-08 03:50:38.862307',469,1),(474,'Progressive overload her hafta kilo artırmak mı demek?','Programımı takip etmeye başladım. Her hafta ağırlık artırmaya çalışıyorum ama bazen form bozuluyor. Progressive overload sadece kilo artırmak mı, yoksa tekrar/set/tempo da sayılır mı?','','soru','2026-05-06 03:50:38.862307',476,2),(475,'Tip 1 diyabeti olan biri Ozempic kullanabilir mi?','Forumda merak ettiğim için soruyorum: Tip 1 diyabet hastalarında Ozempic kullanımı hakkında çok farklı yorumlar görüyorum. Bu konuda genel güvenli yaklaşım nedir?','','soru','2026-05-04 03:50:38.862307',463,4),(476,'Gece antrenmanından sonra ne yemeli?','İşten dolayı çoğu gün 21.30 gibi antrenman bitiyor. Çok ağır yemek uyku kaçırıyor ama hiç yemeyince de aç yatıyorum. Pratik öneriniz var mı?','','soru','2026-05-02 03:50:38.862307',482,1),(477,'Omuz ağrısı olmadan overhead press nasıl ilerletilir?','Overhead press yaparken bazı günler omuz önünde rahatsızlık hissediyorum. Ağrı keskin değil ama ilerletmeye çekiniyorum. Mobilite/ısınma veya alternatif hareket öneriniz var mı?','','soru','2026-04-30 03:50:38.862307',484,2),(478,'Kafeini antrenman öncesi her gün almak mantıklı mı?','Pre-workout kullanmadan sade kahveyle antrenmana gidiyorum. Neredeyse her gün kafein almak tolerans yapar mı? Ara vermek gerekir mi?','','soru','2026-04-28 03:50:38.862307',456,3),(479,'Meal prep yaparken yemekler kaç gün güvenli saklanır?','Pazar günü 4-5 günlük yemek hazırlamak istiyorum. Tavuk, pilav, sebze gibi yemekleri buzdolabında kaç gün saklamak mantıklı? Tadından çok güvenlik kısmını merak ediyorum.','','soru','2026-04-26 03:50:38.862307',481,1),(480,'Antrenmanda RPE kullanmak yeni başlayan için gerekli mi?','Programlarda RPE 7-8 gibi ifadeler görüyorum. Yeni başlayan biri için bu sistemi kullanmak mantıklı mı, yoksa kafayı karıştırır mı?','','soru','2026-04-24 03:50:38.862307',470,2),(481,'Lif artırınca şişkinlik yaşıyorum, nasıl adapte olunur?','Sebze, yulaf ve baklagili artırınca sindirimim zorlanıyor. Lif almak iyi ama şişkinlik günlük hayatı etkiliyor. Kademeli artırmak dışında öneriniz var mı?','','soru','2026-04-21 03:50:38.862307',473,1),(482,'Deload haftası gerçekten gerekli mi?','8 haftadır düzenli çalışıyorum. Son iki antrenmanda performans biraz düştü, eklemler de yorgun gibi. Deload yapmak zaman kaybı mı yoksa planlı toparlanma mı?','','soru','2026-04-19 03:50:38.862307',468,2),(483,'Kahvaltı yapmadan antrenman olur mu?','Sabah erken antrenman yapıyorum ve kahvaltıya zaman kalmıyor. Aç karna çalışmak performansı düşürür mü? Küçük bir şey yemek şart mı?','','soru','2026-04-17 03:50:38.862307',464,1),(484,'Doktorun verdiği ilacı kullanırken supplement almak güvenli mi?','Düzenli ilaç kullanan biri kreatin, magnezyum veya kafein gibi supplementleri eklerken nasıl yaklaşmalı? Genel güvenlik açısından nelere dikkat edilmeli?','','soru','2026-04-15 03:50:38.862307',463,4),(485,'Haftada 10 bin adım hedefi yağ kaybında işe yarıyor mu?','Kalori açığını sadece yemekle kurmak zor geliyor. Günlük adımı 5 binden 10 bine çıkarmak yağ kaybında ciddi fark yaratır mı?','','soru','2026-04-13 03:50:38.862307',459,2),(486,'Evde ekipmansız core çalışması yeterli olur mu?','Salona gidemediğim günlerde core çalışmak istiyorum. Plank, dead bug, side plank gibi hareketler yeterli olur mu, yoksa ağırlık şart mı?','','soru','2026-04-11 03:50:38.862307',477,2),(487,'Kilo aynı kalırken bel incelmesi normal mi?','Son bir aydır tartı pek değişmedi ama bel ölçüm 3 cm azaldı, kıyafetler daha rahat. Bu recomposition olabilir mi, yoksa ölçüm hatası mı?','','soru','2026-04-08 03:50:38.862307',485,1),(488,'Balık yağı kullanırken nelere dikkat edilmeli?','Omega-3 için balık yağı düşünenler var ama marka, EPA/DHA miktarı ve saklama konusu karışık. Nelere bakmak lazım?','','soru','2026-04-05 03:50:38.862307',480,3),(489,'Antrenman sonrası kas ağrısı yoksa gelişim olmuyor mu?','Bazı antrenmanlardan sonra hiç ağrım olmuyor. Bu antrenmanın boşa geçtiği anlamına gelir mi? Kas ağrısını gelişim göstergesi gibi düşünmek doğru mu?','','soru','2026-04-02 03:50:38.862307',467,2),(490,'Akdeniz diyeti vs keto, hangisi daha mantikli?','27 yasindayim, ailede tip 2 diyabet var. Hekimim \'diyet duzelt\' dedi. Akdeniz mi keto mu? Hangisinin uzun donem etkileri daha guvenli?','','soru','2025-09-28 20:24:17.029791',531,1),(491,'Stres yaptigimda dolaba kosuyorum, psikolojik mi metabolik mi?','29 yasinda kadinim, is yerinde cok stresli bir donemim. Aksam eve gelince kontrolsuz yiyorum, tartim 3 ayda 8 kg artti. Hicbir diyet uzun sureli tutamiyorum. Diyetisyene mi gitsem yoksa psikologa mi?','','soru','2026-01-10 06:57:37.803346',466,1),(492,'Karbonhidrat sonrasi sersemleme normal mi?','Pirinc/makarna yedikten 30-40 dk sonra cok yorgun ve sersem hissediyorum. Doktor \'reaktif hipoglisemi olabilir\' dedi ama testler normal. Sizde de oluyor mu? Cozumu nedir?','','soru','2026-04-20 01:28:49.646467',464,1),(493,'Annem kanser tedavisi bitirdi, beslenme rehberi var mi?','Annem 58 yasinda, meme kanseri tedavisini yeni bitirdi. Onkolog \'protein artir, sebze cesidini cogalt\' dedi ama net plan vermedi. Istahi azalmis, sade ama proteinli pratik tarifleri olan var mi?','','soru','2025-08-03 12:21:59.197438',512,1),(494,'Antrenman partnerim cok yavas, ne yapmali?','Spor partnerim baslangic seviyesinde, ben ortanin biraz ustu. 1 saatlik antrenmanim 2.5 saate cikti. Hem onun gelisimi yavas hem benim mola cok. Nasil soyleyebilirim incitmeden?','','soru','2024-11-27 08:42:15.846134',527,2),(495,'Beta-alanin karincanmasi, normal mi?','Pre-workout ucuyorum, elimde-yuzumde karincanmasi var. Etiketinde 2.4 g beta-alanin yaziyor. Bu normal mi yoksa azaltayim mi? Antrenmana fayda mi katiyor gercekten?','','soru','2026-02-14 12:10:29.401195',456,3),(496,'Su tuketimi: gerçekten 3 litre sart mi?','Internette \'gunde 3 litre su ic\' yaziyor her yer. Ben 1.5-2 litre iciyorum, gunluk hayatim normal. 3 litre saglikli mi yoksa abartmis bilim ne diyor?','','soru','2026-01-12 06:12:47.236863',541,1),(497,'Cardio konsepti, zone 2 ne demek?','Zone 2 kosulu bircok yerde okudum, faydalari yiginla yazilmis ama nasil hesaplanir bilmiyorum. Garmin saatim yok, sadece kalp atisi nabiz kemerim var. Pratik olarak nasil olcebilirim?','','soru','2025-05-21 21:01:00.893267',520,2),(498,'Beta bloker kullaniyorum, kalp atisi yukselmiyor','Beta bloker (bisoprolol) kullaniyorum. Antrenmanda kalp atisi 110 u gecmiyor. Zone 2 yapmaya calisiyorum. Hesaplama nasil olmali nabiz hedefinde? Algoritma calismiyor sanki.','','soru','2024-10-13 04:35:17.916882',527,4),(499,'Push-Pull-Legs in pull gunu beni cok yoruyor','PPL 6 gunluk programdayim. Push ve legs idare ediyor ama pull gunlerinde sirt o kadar yoruyor ki ertesi sabah kendimi birakimis hissediyorum. Hacim mi cok, hareket secimi mi yanlis?','','soru','2026-04-09 02:28:58.172309',553,2),(500,'Whey protein kabızlik yapar mi?','1 aydir whey isolate kullaniyorum, sindirim bozuldu, kabızlik var. Laktozsuz seçtigime emindim. Diger marka mi denesem, suya mi gecsem? Bunlar yan etki sayilir mi?','','soru','2025-11-27 09:11:19.261226',536,3),(501,'Kahvalti sart deniyor ama ben sabah hicbir sey istemiyorum','Yillardir sabah midem aci. 12 gibi ilk yemek yiyorum. Buyukler \'kahvalti gunun en onemli ogunu\' diyor. Modern bilim ne diyor, ben hata mi yapiyorum 16:8 yapan biri olarak?','','soru','2025-07-12 21:12:38.161953',527,1),(502,'3 aydir kalori sayiyorum, tartim donmus, deli olucam','31 yasinda kadinim, 67 kg. 1500 kalori aciginda yiyorum, haftada 4 gun spor. Ilk 2 ay 4 kg verdim, son 1 aydir hicbir sey degismedi. Olculer de ayni, adet donemim bile sasti. Bu plato mu yoksa baska bir sey mi?','','soru','2025-12-17 19:05:25.735243',470,1),(503,'Protein hedefini tutturmak icin pratik 5 yiyecek?','Gunluk 130g protein hedefim, ailem yemek pisirmiyor, ev disinda yemek yiyorum cogu zaman. Pratik (hazir/cig olarak alinabilir) yuksek proteinli yiyecek onerilerin nedir?','','soru','2025-10-02 15:48:02.948933',542,1),(504,'Antibiyotik kullanirken antrenmana gitmeli miyim?','Sinüzit icin 7 gunluk antibiyotik basladi. Doktor \'cok zorlamayin\' dedi ama kac gun durmali, hangi yog-unlukta donmeli? Genel kural var mi?','','soru','2026-02-03 19:46:08.400218',543,4),(505,'L-karnitin yag yakimini gercekten hizlandiriyor mu?','Yag yakimi icin L-karnitin almayi dusunuyorum. Internet karisik bilgi veriyor, calisma sonuclari da farkli. Ne dersiniz, bos para mi yoksa fark eder mi?','','soru','2026-03-25 15:20:37.974949',510,3),(506,'Spor salonu uyeligi vs ev gym maliyeti, hangisi karli?','Ay 800 TL salon uyeligi. Eve toplam 35-40 bin TL\'lik kapsamli setup yapabilirim (bench, rack, plate, kettlebell). 4 senede karli mi? Sosyal motivasyon kaybi var mi bunda?','','soru','2026-02-22 05:42:23.588210',520,24),(507,'Ozempic kullaniyorum, antrenmanda baygin hissediyorum','Diyabet icin Ozempic 2 hafta once basladi. Antrenman sonrasi tansiyonum 95-60 a inmis. Kaloriyi artirmak mi gerek yoksa antrenmani azaltmak? Endokrinolog \'sport yap ama dikkatli\' dedi.','','soru','2026-02-24 10:42:01.195223',543,4),(508,'Antrenmana 2 saat ayirsam, sadece 50 dk yapmaktan farki ne?','Salonda gozlemledigim sey: cogu kisi telefonla 2-3 saat yatiyor sette set arasi. Ben 50 dk de bitirdigim seyi onlar 2.5 saatte yapiyor. Yogun ve kisa mi, uzun ve casual mi daha iyi?','','soru','2026-02-04 01:41:27.857941',466,2),(509,'Bel kalinligimi diet ile mi yoksa egzersiz ile mi inecek?','32 yasinda erkek, son 1 yilda bel 89 a cikti. Karin egzersizleri yaptim, hic fark yok. Kalori acigi mi sart yoksa hedeflenmis core calismasi yetiyor mu? Spot reduction mit mi?','','soru','2026-04-03 09:54:36.776934',543,1),(510,'Bench press te omzum acidi, alternatif hareketler?','1 ay onceki bench sirasinda sol omuzda sislik benzeri agri. Doktor \'overuse\' dedi, 4 hafta dinlen, sonra alternatif hareketlerle baslayabilirsin dedi. Hangi pressing alternatifi omuz dostudur?','','soru','2026-04-18 00:12:51.551071',461,2),(511,'Statin kullaniyorum, kas eridi gibi hissediyorum','65 yas babam statin (atorvastatin) kullaniyor. Bacak agrilari var. CK degeri normal. Doktor \'devam et\' diyor. Spor yaparsa daha mi kotu olur? Doza ya da ilaca alternatif olur mu acaba?','','soru','2025-07-15 08:29:24.403409',530,4),(512,'Adetimde aksilemi gidermek icin agri kesici, kas gelisimini engeller mi?','Adet dönemde naproxen aliyorum 2 gun (cok ag-ridan dolayi). Ibuprofen / naproxen kullanim antrenman sonrasi tam o gun mu, sonra mi? Kas gelişimini frenler mi araştirmalar ne diyor?','','soru','2026-04-10 11:12:00.418155',512,4),(513,'Doktorum oruc tut dedi, 16:8 mi 18:6 mi?','Insulin direnci tanim var, hekimim aralikli oruc onerdi. Yontem secimi bana kaldi. Su an 16:8 deniyorum, aksam 8 sabah 12 arasi. Calismayan biri 18:6 mi denemeli? Spor zamanini neye gore ayarlamali?','','soru','2026-01-04 16:37:09.112349',489,1),(514,'8 haftadir progress yok, deload yapmali miyim?','Squat 130 kg da, bench 95 te, deadlift 160 ta sikistim 8 haftadir. Beslenme cut\'ta degil, uyku yeterli (7+). Deload denedinmi olan var mi? Bir hafta isten kalan herkes oluyor mu?','','soru','2025-12-29 16:43:19.862790',466,2),(515,'48 yasindayim, ilk kez gym e gicegim, ne hata yapmamaliyim?','Yasamim boyu spor yapmadim, doktor \'hareket et yoksa kotuye gidicek\' dedi. Pazartesi ilk gunum. Hangi hatalardan kacinmaliyim, neyle baslamaliyim? Cok mahcup hissediyorum aslinda.','','soru','2025-08-15 09:04:16.454064',530,2),(516,'Hamilelikten 4 yil sonra hala fazla kilolarim var','33 yasinda, ikinci cocugumdan sonra 14 kg fazla kaldi. Emzirme bitti, simdi diyete baslamak istiyorum ama hangi yontem? Cok cabuk yorgun olmamayi istiyorum cunku iki cocuga bakiyorum.','','soru','2026-03-15 23:28:29.052829',550,1),(517,'Magnezyum glisinat mi sitrat mi, hangisi uyku icin?','Uyku icin magnezyum almak istiyorum. Glisinat, sitrat, malat, taurat... 4 form gorebiliyorum. Hangisi uyku, hangisi kabızlik? Pratik fark var mi normal kullanicilar icin?','','soru','2025-01-25 12:31:33.375914',551,3),(518,'Egzersiz sonrasi neden uyuyamiyorum?','Aksam 20-21 arasi yog-un antrenman sonrasi gece 12 ye kadar uyuyamiyorum. Magnezyum, kafeinsiz, ekran az... bircok seyi denedim. Sabaha antrenman alsam mi yoksa cozumu olan var mi?','','soru','2025-10-05 03:53:23.829389',542,2),(519,'Squat sirasinda dizim catirdiyor, durmam mi devam mi etmem mi?','Squat\'larin alt kismi sirasinda sol dizimde catir cutur sesi var, ama agri yok. Devam etmeli miyim yoksa fizyoterapist mi? 30 yas erkek, 6 aydir antrenman, 80 kg ile 4x8 yapiyorum.','','soru','2026-05-18 13:34:53.155736',505,2),(520,'Vegan oldum, B12 ve demir takip ediyor musunuz?','6 aydir veganim, son tahlillerde B12 dusuk, demir sinir degerde. Ferritin 18. Supplement aliyorum ama emin degilim. Vegan beslenmede hangi tahlilleri rutin yaptiriyorsunuz?','','soru','2025-10-15 11:35:09.511584',551,1),(521,'Hashimato ile selenyum nasil kullanilir?','Hashimato tanim var. Endokrinolog selenyum oneriyor (200 mcg). Marka secerken nelere bakmali? Belirli zamanda mi almali, ac karna mi tok?','','soru','2026-03-01 20:59:38.294405',470,3),(522,'Anneme spor yaptirmak istiyorum, 62 yasinda nereden baslayalim?','Annem 62, kalp problemi yok ama sedanter. Doktor \'hareket et\' diyor. Yuruyus disinda evde yapabilecegi guvenli hareketler nelerdir? Saglik beklentilerim icin oneri?','','soru','2026-04-07 17:30:20.609189',487,24),(523,'Calisthenics ile gercek anlamda kas kazanilabilir mi?','Spor salonu uyeligi pahali, dipper baremm var, kettlebell var evde. Sirf vucut agirligi + temel ekipmanla cidi kas kazanan oldu mu? Bilek/dirsek dayanikligi nasil korunuyor uzun vadede?','','soru','2026-04-23 09:22:25.046285',499,2),(524,'Antrenman gunlugu tutmak gercekten gerekli mi?','Herkes Excel veya app oneriyor. Ben aklimdan ne yaptig-imi takip ediyorum. Yazmak gercekten progress\'i hizlandirir mi? Yoksa overplanning\'in psikolojik yorgunlugu daha mi cok?','','soru','2025-11-30 08:03:32.108730',512,24),(525,'Saglikli kosu nasil olur, glutum yok','1 km kosuyorum, nefes degil bacaklarim arzeve geliyor (ozellikle quad). Glutum sanki uykuda. Form sorunu mu? Bunu duzeltmek icin neye odaklanmaliyim?','','soru','2025-12-21 07:43:48.702002',464,2),(526,'D vitaminim 18, doktor 50.000 IU yazdi, normal mi?','Son tahlilde D vitamini 18 ng/mL cikti. Doktor 8 hafta 50.000 IU haftalik dedi. Bu cok mu degil mi? Aldigim bilgilerle çakişiyor. Risk var mi?','','soru','2026-05-17 05:35:31.099067',550,3),(527,'Kreatin yukleme yapma hatasi diyorlar, gercek mi?','5 g/gun kreatin alacaktim, ama bir antrenor \'yukleme yap\' dedi. Diger video \'20g 5 gun gereksiz\' diyor. Kim hakli? 4 hafta da 70 kg luk biri icin tam doz nedir?','','soru','2026-05-12 05:25:22.106555',529,3),(528,'BCAA mi EAA mi, hangisi para yatirimini hak eder?','Antrenman sirasinda BCAA aliyordum, son zamanda EAA daha iyi cikiyor diye. Fiyat 2 kat. Gunluk proteinim 130g zaten. Bu durumda intra-workout sart mi gercekten?','','soru','2026-03-24 08:51:28.815530',526,3),(529,'Spor salonu sosyal anksiyetesi olan biri olarak nasil baslanir?','27, sosyal anksiyete tanim var. Salona girip cikmak isteyemiyorum, herkes bakiyor sanki. Online program + ev mi denesem? Yoksa kucuk bir butik salon mu? Deneyimi olan var mi?','','soru','2025-01-17 11:18:14.193742',551,24),(530,'Antidepresan basladim, antrenmana etkisi var mi?','Sertralin 50 mg, 3 haftadir kullaniyorum. Antrenmanda enerji daha az, son tekrarlarda erkenden bitiyorum. Bu ilac etkisi mi? Doktora sormak istiyorum ama bu forumda yasayan var mi?','','soru','2026-05-14 11:04:35.462652',464,4),(531,'Diet kola, zero kalori ama insulin yukseltir mi?','Gunde 1 litre kadar diet kola iciyorum. Kalorisi sifir biliyorum ama sucralose insulin yukseltir mi gercekten? Bilim ne diyor, deneyimi olanlar ne diyor?','','soru','2026-03-13 11:53:44.377261',553,1),(532,'Yumurta sarisinda kolesterol kotu mu iyi mi, kafam karisti','Yillarca \'sarisini yeme\' dedi annem. Simdi araştirinca dietary cholesterol kan kolesterolunu pek etkilemiyor diyor. Gunde 3 yumurta yiyorum, tehlikeli mi 35 yaslarinda biri icin?','','soru','2025-12-17 17:32:04.555399',466,1),(533,'Genetik antrenman tipim nedir, nasil ogrenirim?','Bazi insanlar dayanikliliga, bazilari hiza, bazilari kuvvete egilimli diyorlar. 23 yasinda, fitness yolculugu basinda biri olarak hangi yontemle \'genetik avantajimi\' anlayabilirim? Test mi mantikli yoksa deneme/yanilma mi?','','soru','2025-11-08 21:59:13.695250',542,24),(534,'Yag oraninin DEXA olcumu ile tartiyi karsilastirmak mantikli mi?','Gecen ay DEXA yaptirdim, %22 yag dediler. Ev tartisi (biyoempedans) %28 diyor. Hangisine gore takip etmeliyim? Su an cut yapiyorum, dogru veriyle ilerlemek lazim.','','soru','2025-08-25 07:53:57.785331',497,1),(535,'Egzersizi haftada kac kez tekrar etmek yeterli kas kazandirir?','Bence buyuk kas gruplari icin 2x/hafta yeterli (gogus, sirt, bacak). Bicep icin de 2x. Yine de cogu source \'sik yap daha cok\' diyor. Tek lineer mi, dalgali mi? Yeni gelisme nedir bu konuda?','','soru','2025-09-24 22:32:25.732400',548,2);
