INSERT INTO `yorumlar` (`id`, `mesaj`, `tarih`, `icerik_id`, `yazar_id`, `parent_id`, `depth`) VALUES (24,'Vaktinizi ayırıp bloğumuzu incelediğiniz için teşekkür ederim. İlginiz bizim için değerlidir.','2026-03-01 09:06:19.920841',5,3,23,1),(31,'fazla yerseniz şişkinlik yapabilir.','2026-03-02 15:15:02.978678',5,3,30,1),(62,'Güncel araştırmalara göre Ozempic, Tip 1 diyabet hastaları için uygun değildir. Tip 1 diyabette pankreas insülin üretemez; bu nedenle hastaların insülin iğnesi kullanması gerekir. Ozempic ise bir insülin değildir; etkin maddesi semaglutid olan, GLP‑1 reseptör agonistleri sınıfına giren ve haftada bir uygulanan bir enjeksiyon ilacıdır.','2026-03-12 13:31:33.060016',10,3,61,1),(79,'sel','2026-05-18 07:35:30.833869',15,3,78,1),(84,'he','2026-05-18 17:59:59.054892',15,3,79,2),(3146,'Ben en büyük farkı akşam öğününe daha fazla hacimli sebze ekleyince gördüm. Yoğurt, salata ve çorba üçlüsü kalori düşükken tok tutuyor.','2026-05-22 05:50:38.862307',466,457,NULL,0),(3147,'Ben kaloriden cok makro dagilima onem veriyorum.','2026-05-22 11:50:38.862307',466,459,3146,1),(3148,'Gün içinde kaloriyi çok kısmak akşamı patlatıyor olabilir. Öğleye 150-200 kcal ekleyip akşam krizinin azalıp azalmadığına bakardım.','2026-05-22 10:01:38.862307',466,466,NULL,0),(3149,'Diyetisyenim de tam boyle yorumlamisti, onayliyorum.','2026-05-22 18:01:38.862307',466,456,3148,1),(3150,'Bende uyku saati de etkiliyor. Geç yatınca açlık daha çok hissediliyor. Bitki çayı + erken uyku basit ama işe yarıyor.','2026-05-22 14:12:38.862307',466,485,NULL,0),(3151,'Vegan birisi olarak bu konu farkli geliyor bana.','2026-05-23 02:12:38.862307',466,475,3150,1),(3152,'Açlık çok sertse açığı biraz küçültmek daha sürdürülebilir olabilir. Haftalık ortalama ilerleme iyiyse her gün zorlamaya gerek yok.','2026-05-22 18:23:38.862307',466,456,NULL,0),(3153,'Vegan birisi olarak bu konu farkli geliyor bana.','2026-05-22 23:23:38.862307',466,464,3152,1),(3154,'Haftada 3 gün için full body daha iyi oturur. Hareketleri daha sık tekrar edersin ve teknik daha hızlı gelişir.','2026-05-20 05:50:38.862307',467,470,NULL,0),(3155,'Hareket coğunluğu kişi yas grubuna gore deg-isir bence.','2026-05-20 13:50:38.862307',467,474,3154,1),(3156,'PPL genelde 5-6 gün gidince anlamlı oluyor. 3 günde PPL yaparsan her kası haftada bir görmüş olursun.','2026-05-20 10:01:38.862307',467,476,NULL,0),(3157,'Calisma hacminin de hesaba katilmasi lazim.','2026-05-20 14:01:38.862307',467,468,3156,1),(3158,'Ben 2 ay full body yapıp sonra upper-lower\'a geçtim. Başta az hareket ama kaliteli form daha rahat ilerletiyor.','2026-05-20 14:12:38.862307',467,479,NULL,0),(3159,'Hareket coğunluğu kişi yas grubuna gore deg-isir bence.','2026-05-21 02:12:38.862307',467,477,3158,1),(3160,'Programdan çok takip edebilmek önemli. Squat, hip hinge, itiş, çekiş ve core hareketleri varsa başlangıç için yeterli.','2026-05-20 18:23:38.862307',467,458,NULL,0),(3161,'Periyodizasyon bu konuda anahtardir, lineer ilerleme tek yol degil.','2026-05-21 04:23:38.862307',467,460,3160,1),(3162,'Kreatinde asıl konu düzenli almak. Günlük 3-5 g alıp devam etmek zamanlamadan daha önemli.','2026-05-18 05:50:38.862307',468,466,NULL,0),(3163,'Bilimsel kanit yetersizdir cogu supplement icin, plasebo etkisi yuksek.','2026-05-18 12:50:38.862307',468,456,3162,1),(3164,'Ben kahvaltıyla alıyorum, midemi rahatsız etmiyor. Antrenman saatim değişse de unutmadığım için böyle daha kolay.','2026-05-18 10:01:38.862307',468,483,NULL,0),(3165,'Bilimsel kanit yetersizdir cogu supplement icin, plasebo etkisi yuksek.','2026-05-18 20:01:38.862307',468,481,3164,1),(3166,'Performans etkisi kafein gibi akut değil. Kas kreatin depoları doldukça faydasını görüyorsun.','2026-05-18 14:12:38.862307',468,458,NULL,0),(3167,'Bazi supplementler ilac etkisinde duruyor, hekime mutlaka soyle.','2026-05-19 02:12:38.862307',468,476,3166,1),(3168,'Bol su içmeyi unutma. Bende tek sorun ilk hafta düzenli su içmeyince şişkin hissetmem olmuştu.','2026-05-18 18:23:38.862307',468,467,NULL,0),(3169,'Tek bir supplement degil dengeli beslenme her zaman daha guvenli.','2026-05-19 04:23:38.862307',468,471,3168,1),(3170,'Şart değil, adı üstünde takviye. Besinden tamamlıyorsan gayet olur. Eksik kaldığın günlerde pratik çözüm.','2026-05-16 05:50:38.862307',469,469,NULL,0),(3171,'Bilimsel kanit yetersizdir cogu supplement icin, plasebo etkisi yuksek.','2026-05-16 13:50:38.862307',469,457,3170,1),(3172,'Bulk döneminde iştah sorun değilse besin daha keyifli. Cut döneminde whey düşük kalorili olduğu için işime yarıyor.','2026-05-16 10:01:38.862307',469,462,NULL,0),(3173,'Bazi markalar 3rd party test ediyor, onlari secmek lazim.','2026-05-16 20:01:38.862307',469,478,3172,1),(3174,'Ben yoğurt + yulaf + whey şeklinde ara öğün yapıyorum. Ama bütçe kısıtlıysa önce normal besini düzene sokardım.','2026-05-16 14:12:38.862307',469,481,NULL,0),(3175,'Doktor onayi olmadan supplement risk olur, dogru soyluyor.','2026-05-17 01:12:38.862307',469,459,3174,1),(3176,'Laktoz hassasiyetin varsa ürün seçimine dikkat et. İzole whey bazı kişilerde daha rahat oluyor ama daha pahalı.','2026-05-16 18:23:38.862307',469,472,NULL,0),(3177,'Dizlerin öne gitmesi tek başına hata değil. Topuk yerde kalıyor, bel pozisyonu korunuyor ve ağrı yoksa sorun olmayabilir.','2026-05-14 05:50:38.862307',470,468,NULL,0),(3178,'Sakatlanma riski bu yontemde daha yuksek bence.','2026-05-14 09:50:38.862307',470,458,3177,1),(3179,'Ayak bileği mobilitesi de etkiliyor. Topuk yükseliyorsa mobilite veya stance ayarı denenebilir.','2026-05-14 10:01:38.862307',470,477,NULL,0),(3180,'Toparlanma 24-48 saat surer, bu zamanlamayi atlamamali.','2026-05-14 17:01:38.862307',470,461,3179,1),(3181,'Video çekip yandan ve önden bakmak en iyisi. Sözlü yorumlar bazen eski ezberden geliyor.','2026-05-14 14:12:38.862307',470,456,NULL,0),(3182,'Eklem sagligi 30 yas sonrasi cok onemli oluyor.','2026-05-15 01:12:38.862307',470,460,3181,1),(3183,'Ben goblet squat ile formu oturtunca barbell squat daha rahatladı. Hafif kil